// StroppyAPIHandler is an implementation of the api.StroppyAPI service.
type StroppyAPIHandler interface {
	// Submit a test suite for execution. Returns immediately with a run ID.
	RunTestSuite(context.Context, *connect.Request[api.RunTestSuiteRequest]) (*connect.Response[api.RunTestSuiteResponse], error)
	// Cancel a running workflow.
	CancelRun(context.Context, *connect.Request[api.CancelRunRequest]) (*connect.Response[api.CancelRunResponse], error)
	// Get full run details including DAG shape and task statuses.
	GetRun(context.Context, *connect.Request[api.GetRunRequest]) (*connect.Response[api.GetRunResponse], error)
	// List workflow runs with pagination and filtering.
	ListRuns(context.Context, *connect.Request[api.ListRunsRequest]) (*connect.Response[api.ListRunsResponse], error)
	// List test suites with pagination and filtering.
	ListSuites(context.Context, *connect.Request[api.ListSuitesRequest]) (*connect.Response[api.ListSuitesResponse], error)
	// Get suite details including its child runs.
	GetSuite(context.Context, *connect.Request[api.GetSuiteRequest]) (*connect.Response[api.GetSuiteResponse], error)
	// Stream live run updates — task status changes and logs (server streaming).
	StreamRun(context.Context, *connect.Request[api.StreamRunRequest], *connect.ServerStream[api.StreamRunUpdate]) error
	// Get current settings.
	GetSettings(context.Context, *connect.Request[api.GetSettingsRequest]) (*connect.Response[api.GetSettingsResponse], error)
	// Update settings.
	UpdateSettings(context.Context, *connect.Request[api.UpdateSettingsRequest]) (*connect.Response[api.UpdateSettingsResponse], error)
	// Compare metrics of two runs via PromQL queries against Grafana/Prometheus.
	CompareRuns(context.Context, *connect.Request[api.CompareRunsRequest]) (*connect.Response[api.CompareRunsResponse], error)
	// Validate a database topology template. Returns structural issues instantly.
	ValidateTopology(context.Context, *connect.Request[api.ValidateTopologyRequest]) (*connect.Response[api.ValidateTopologyResponse], error)
	// Dry run — full pre-flight check including cloud quotas, image availability, etc.
	DryRun(context.Context, *connect.Request[api.DryRunRequest], *connect.ServerStream[api.DryRunCheck]) error
	// Authenticate with username and password. Returns JWT access + refresh tokens.
	Login(context.Context, *connect.Request[api.LoginRequest]) (*connect.Response[api.LoginResponse], error)
	// Refresh an expired access token using a refresh token.
	RefreshToken(context.Context, *connect.Request[api.RefreshTokenRequest]) (*connect.Response[api.RefreshTokenResponse], error)
	// Invalidate the current session.
	Logout(context.Context, *connect.Request[api.LogoutRequest]) (*connect.Response[api.LogoutResponse], error)
	// Get the currently authenticated user.
	GetCurrentUser(context.Context, *connect.Request[api.GetCurrentUserRequest]) (*connect.Response[api.GetCurrentUserResponse], error)
	// Register a new workload (upload script + auto-probe).
	RegisterWorkload(context.Context, *connect.Request[api.RegisterWorkloadRequest]) (*connect.Response[api.RegisterWorkloadResponse], error)
	// List registered workloads with metadata.
	ListWorkloads(context.Context, *connect.Request[api.ListWorkloadsRequest]) (*connect.Response[api.ListWorkloadsResponse], error)
	// Get workload details including probe result.
	GetWorkload(context.Context, *connect.Request[api.GetWorkloadRequest]) (*connect.Response[api.GetWorkloadResponse], error)
	// Delete a workload from the registry.
	DeleteWorkload(context.Context, *connect.Request[api.DeleteWorkloadRequest]) (*connect.Response[api.DeleteWorkloadResponse], error)
	// Probe a script without saving — returns extracted metadata.
	ProbeScript(context.Context, *connect.Request[api.ProbeScriptRequest]) (*connect.Response[api.ProbeScriptResponse], error)
	// Create a reusable topology template.
	CreateTopologyTemplate(context.Context, *connect.Request[api.CreateTopologyTemplateRequest]) (*connect.Response[api.CreateTopologyTemplateResponse], error)
	// List topology templates with optional database type filter.
	ListTopologyTemplates(context.Context, *connect.Request[api.ListTopologyTemplatesRequest]) (*connect.Response[api.ListTopologyTemplatesResponse], error)
	// Get a topology template by ID.
	GetTopologyTemplate(context.Context, *connect.Request[api.GetTopologyTemplateRequest]) (*connect.Response[api.GetTopologyTemplateResponse], error)
	// Update an existing topology template.
	UpdateTopologyTemplate(context.Context, *connect.Request[api.UpdateTopologyTemplateRequest]) (*connect.Response[api.UpdateTopologyTemplateResponse], error)
	// Delete a topology template.
	DeleteTopologyTemplate(context.Context, *connect.Request[api.DeleteTopologyTemplateRequest]) (*connect.Response[api.DeleteTopologyTemplateResponse], error)
}

